a new React Native project using `npx create-react-native-app`. Then, add the following code to the `src` folder:
```
import React, { useState } from 'react';
import { View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import * as Anonymizer from 'anonymizer-react-native';

const CyberBully = () => {
  const [message, setMessage] = useState('');
  const [username, setUsername] = useState('');

  const handleSubmit = async () => {
    if (message && username) {
      const anonymizedMessage = Anonymizer.anonymize(message);
      const anonymizedUsername = Anonymizer.anonymize(username);

      // Do something with the anonymized message and username
      console.log(`Anonymized message: ${anonymizedMessage}`);
      console.log(`Anonymized username: ${anonymizedUsername}`);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.message}>Enter a message:</Text>
      <TextInput
        style={styles.input}
        value={message}
        onChangeText={setMessage}
        placeholder="Type a message..."
      />
      <Text style={styles.username}>Enter a username:</Text>
      <TextInput
        style={styles.input}
        value={username}
        onChangeText={setUsername}
        placeholder="Type a username..."
      />
      <TouchableOpacity onPress={handleSubmit}>
        <Text style={styles.submit}>Submit</Text>
      </TouchableOpacity>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    justifyContent: 'center',
    alignItems: 'center',
  },
  message: {
    fontSize: 18,
    marginVertical: 10,
  },
  input: {
    height: 40,
    borderColor: 'gray',
    borderWidth: 1,
    paddingVertical: 10,

